// Prepara el log de lo que se expiró para debugging y auditoría
const rows = $input.all().map(i => i.json);
const resumen = rows.map(r =>
  `#${r.id} ${r.pedido_codigo || 'sin-codigo'} (rest:${r.restaurante_id})`
).join(', ');

console.log(`[Cron Expirar Pedidos] ${rows.length} pedido(s) expirado(s): ${resumen}`);

return [{
  json: {
    total_expirados: rows.length,
    pedidos:         rows.map(r => ({
      id:             r.id,
      pedido_codigo:  r.pedido_codigo,
      restaurante_id: r.restaurante_id,
      telefono:       r.telefono,
      expirado_at:    r.updated_at
    }))
  }
}];

// No hubo pedidos expirados en esta ejecución — noop silencioso
console.log('[Cron Expirar Pedidos] Sin pedidos que expirar.');
return [{ json: { total_expirados: 0 } }];
